// Flutter imports:
import 'package:flutter/material.dart';

// Package imports:
import 'package:hooks_riverpod/hooks_riverpod.dart';

// Project imports:
import 'package:baseball_detector_flutter/controllers/maintenance_controller.dart';
import 'package:baseball_detector_flutter/data/models/maintenance_state.dart';
import 'package:baseball_detector_flutter/l10n/l10n_ext.dart';
import 'package:baseball_detector_flutter/utils/date.dart';
import 'package:baseball_detector_flutter/views/components/custom_button.dart';
import 'package:baseball_detector_flutter/views/components/custom_loading_indicator.dart';
import 'package:baseball_detector_flutter/views/components/login_layout.dart';
import 'package:baseball_detector_flutter/views/themes/font_manager.dart';

class MaintenancePage extends ConsumerWidget {
  const MaintenancePage({super.key});

  @override
  Widget build(BuildContext context, WidgetRef ref) {
    final maintenanceState = ref.watch(maintenanceControllerProvider);

    return LoginLayout(
      child: SingleChildScrollView(
        child: Column(
          crossAxisAlignment: CrossAxisAlignment.stretch,
          children: [
            Text(
              context.l10n.maintenance_page__title,
              style: TextStyleManager.headline4,
            ),
            Text(
              context.l10n.maintenance_page__description,
              style: TextStyleManager.subtitle1,
            ),
            const SizedBox(height: 32),
            ...switch (maintenanceState) {
              CheckingMaintenance() => [const CustomLoadingIndicator()],
              Operational() => [
                  _buildReloadButton(context, ref),
                ],
              InMaintenance() => [
                  ..._buildMaintenanceContent(context, maintenanceState.message,
                      maintenanceState.estimatedEndTime),
                  const SizedBox(height: 16),
                  _buildReloadButton(context, ref),
                ],
              MaintenanceError() => [
                  Text(
                    maintenanceState.message,
                    style: TextStyleManager.body1,
                  ),
                  const SizedBox(height: 16),
                  _buildReloadButton(context, ref),
                ],
            }
          ],
        ),
      ),
    );
  }

  Iterable<Widget> _buildMaintenanceContent(
    BuildContext context,
    String? message,
    DateTime? estimatedEndTime,
  ) {
    final items = <Widget>[];

    // メンテナンスメッセージ
    if (message != null && message.isNotEmpty) {
      items.add(
        Text(
          message,
          style: TextStyleManager.body1,
        ),
      );
      items.add(const SizedBox(height: 8));
    }

    // 終了予定時刻
    if (estimatedEndTime != null) {
      items.add(
        Text(
          context.l10n.maintenance_page__until +
              dateTimeToString(
                timestamp: estimatedEndTime,
                locale: Localizations.localeOf(context).languageCode,
                template: context.l10n.datetime_format,
              ),
          style: TextStyleManager.body1,
        ),
      );
    }

    return items;
  }

  Widget _buildReloadButton(BuildContext context, WidgetRef ref) {
    return CustomButton(
      variant: CustomButtonVariant.primary,
      onPressed: () => ref.invalidate(maintenanceControllerProvider),
      text: context.l10n.maintenance_page__reload,
    );
  }
}

