// Package imports:
import 'package:flutter_test/flutter_test.dart';
import 'package:hooks_riverpod/hooks_riverpod.dart';

// Project imports:
import 'package:baseball_detector_flutter/controllers/maintenance_controller.dart';
import 'package:baseball_detector_flutter/data/clients/static_file_client_fake.dart';
import 'package:baseball_detector_flutter/data/models/failure/failure.dart';
import 'package:baseball_detector_flutter/data/models/maintenance_info.dart';
import 'package:baseball_detector_flutter/data/models/maintenance_info_dummy.dart';
import 'package:baseball_detector_flutter/data/models/maintenance_state.dart';
import 'package:baseball_detector_flutter/providers/static_file_client_provider.dart';

void main() {
  TestWidgetsFlutterBinding.ensureInitialized();

  late ProviderContainer container;
  late FakeStaticFileClient fakeStaticFileClient;

  setUp(() {
    fakeStaticFileClient = FakeStaticFileClient();
    container = ProviderContainer(
      overrides: [
        staticFileClientProvider.overrideWithValue(fakeStaticFileClient),
      ],
    );
  });

  tearDown(() {
    fakeStaticFileClient.reset();
    container.dispose();
  });

  group('MaintenanceController', () {
    group('初期化', () {
      test('初期状態は Checking', () {
        final state = container.read(maintenanceControllerProvider);
        expect(state, isA<CheckingMaintenance>());
      });
    });

    group('メンテナンス情報取得', () {
      test('運用中の場合 Operational を返す', () async {
        // Arrange
        fakeStaticFileClient.setMaintenanceInfo(
          MaintenanceInfoDummy.operational,
        );

        // Act
        final controller =
            container.read(maintenanceControllerProvider.notifier);
        await controller.startObserving(true);

        // Assert
        final state = container.read(maintenanceControllerProvider);
        expect(state, isA<Operational>());
      });

      test('メンテナンス中の場合 InMaintenance を返す', () async {
        // Arrange
        fakeStaticFileClient.setMaintenanceInfo(
          MaintenanceInfoDummy.currentMaintenanceWithEndTime,
        );

        // Act
        final controller =
            container.read(maintenanceControllerProvider.notifier);
        await controller.startObserving(true);

        // Assert
        final state = container.read(maintenanceControllerProvider);
        expect(state, isA<InMaintenance>());
        final inMaintenance = state as InMaintenance;
        expect(inMaintenance.message, 'システムアップデートのためメンテナンス中です');
        expect(inMaintenance.estimatedEndTime, isNotNull);
      });

      test('メンテナンス中でスケジュール情報がない場合、デフォルトメッセージを返す', () async {
        // Arrange
        fakeStaticFileClient.setMaintenanceInfo(
          MaintenanceInfoDummy.maintenanceWithoutSchedule,
        );

        // Act
        final controller =
            container.read(maintenanceControllerProvider.notifier);
        await controller.startObserving(true);

        // Assert
        final state = container.read(maintenanceControllerProvider);
        expect(state, isA<InMaintenance>());
        final inMaintenance = state as InMaintenance;
        expect(inMaintenance.message, 'System is currently under maintenance');
        expect(inMaintenance.estimatedEndTime, isNull);
      });

      test('API エラーの場合 MaintenanceError を返す', () async {
        // Arrange
        final failure = Failure.undefined(
          code: 'TEST_ERROR',
        );
        fakeStaticFileClient.setMaintenanceFailure(failure);

        // Act
        final controller =
            container.read(maintenanceControllerProvider.notifier);
        await controller.startObserving(true);

        // Assert
        final state = container.read(maintenanceControllerProvider);
        expect(state, isA<MaintenanceError>());
        final maintenanceError = state as MaintenanceError;
        expect(maintenanceError.message, 'Unknown error.');
      });
    });

    group('メンテナンススケジュール判定', () {
      test('現在時刻が範囲内のスケジュールを正しく選択する', () async {
        // Arrange
        fakeStaticFileClient.setMaintenanceInfo(
          MaintenanceInfoDummy.multipleSchedules,
        );

        // Act
        final controller =
            container.read(maintenanceControllerProvider.notifier);
        await controller.startObserving(true);

        // Assert
        final state = container.read(maintenanceControllerProvider);
        expect(state, isA<InMaintenance>());
        final inMaintenance = state as InMaintenance;
        expect(inMaintenance.message, '現在実行中のメンテナンス');
      });

      test('since が null の場合、開始時刻制限なしとして扱う', () async {
        // Arrange
        fakeStaticFileClient.setMaintenanceInfo(
          MaintenanceInfoDummy.noStartTimeLimit,
        );

        // Act
        final controller =
            container.read(maintenanceControllerProvider.notifier);
        await controller.startObserving(true);

        // Assert
        final state = container.read(maintenanceControllerProvider);
        expect(state, isA<InMaintenance>());
        final inMaintenance = state as InMaintenance;
        expect(inMaintenance.message, '臨時メンテナンス中');
      });

      test('until が null の場合、終了時刻制限なしとして扱う', () async {
        // Arrange
        fakeStaticFileClient.setMaintenanceInfo(
          MaintenanceInfoDummy.currentMaintenanceNoEndTime,
        );

        // Act
        final controller =
            container.read(maintenanceControllerProvider.notifier);
        await controller.startObserving(true);

        // Assert
        final state = container.read(maintenanceControllerProvider);
        expect(state, isA<InMaintenance>());
        final inMaintenance = state as InMaintenance;
        expect(inMaintenance.message, '緊急メンテナンス中です');
      });
    });

    group('多言語対応', () {
      test('日本語メッセージを優先して取得する', () async {
        // Arrange
        fakeStaticFileClient.setMaintenanceInfo(
          MaintenanceInfoDummy.multiLanguageMessages,
        );

        // Act
        final controller =
            container.read(maintenanceControllerProvider.notifier);
        await controller.startObserving(true);

        // Assert
        final state = container.read(maintenanceControllerProvider);
        expect(state, isA<InMaintenance>());
        final inMaintenance = state as InMaintenance;
        expect(inMaintenance.message, 'システムメンテナンス中です');
      });

      test('日本語がない場合は英語を取得する', () async {
        // Arrange
        fakeStaticFileClient.setMaintenanceInfo(
          MaintenanceInfoDummy.englishOnlyMessage,
        );

        // Act
        final controller =
            container.read(maintenanceControllerProvider.notifier);
        await controller.startObserving(true);

        // Assert
        final state = container.read(maintenanceControllerProvider);
        expect(state, isA<InMaintenance>());
        final inMaintenance = state as InMaintenance;
        expect(inMaintenance.message, 'System maintenance - English only');
      });

      test('日本語も英語もない場合は最初の値を取得する', () async {
        // Arrange
        fakeStaticFileClient.setMaintenanceInfo(
          MaintenanceInfoDummy.noJapaneseEnglishMessage,
        );

        // Act
        final controller =
            container.read(maintenanceControllerProvider.notifier);
        await controller.startObserving(true);

        // Assert
        final state = container.read(maintenanceControllerProvider);
        expect(state, isA<InMaintenance>());
        final inMaintenance = state as InMaintenance;
        expect(inMaintenance.message, 'Maintenance en français'); // 最初の値
      });

      test('description が null の場合はメッセージも null', () async {
        // Arrange
        fakeStaticFileClient.setMaintenanceInfo(
          MaintenanceInfoDummy.noDescription,
        );

        // Act
        final controller =
            container.read(maintenanceControllerProvider.notifier);
        await controller.startObserving(true);

        // Assert
        final state = container.read(maintenanceControllerProvider);
        expect(state, isA<InMaintenance>());
        final inMaintenance = state as InMaintenance;
        expect(inMaintenance.message, isNull);
      });
    });

    group('タイマー管理', () {
      test('startObserving でタイマーが開始される', () async {
        // Arrange
        fakeStaticFileClient.setMaintenanceInfo(
          MaintenanceInfoDummy.operational,
        );

        // Act
        final controller =
            container.read(maintenanceControllerProvider.notifier);
        await controller.startObserving(false); // refreshImmediately = false

        // Assert
        // タイマーが設定されていることを間接的に確認
        // （直接アクセスできないため、動作で確認）
        expect(() => controller.stopObserving(), returnsNormally);
      });

      test('stopObserving でタイマーが停止される', () async {
        // Arrange
        fakeStaticFileClient.setMaintenanceInfo(
          MaintenanceInfoDummy.operational,
        );

        // Act
        final controller =
            container.read(maintenanceControllerProvider.notifier);
        await controller.startObserving(false);
        controller.stopObserving();

        // Assert
        // stopObserving が正常に呼び出されることを確認
        expect(() => controller.stopObserving(), returnsNormally);
      });

      test('startObserving を再度呼び出すと前のタイマーが停止される', () async {
        // Arrange
        fakeStaticFileClient.setMaintenanceInfo(
          MaintenanceInfoDummy.operational,
        );

        // Act
        final controller =
            container.read(maintenanceControllerProvider.notifier);
        await controller.startObserving(false);
        await controller.startObserving(false); // 再度呼び出し

        // Assert
        // 正常に呼び出されることを確認
        expect(() => controller.stopObserving(), returnsNormally);
      });
    });

    group('ライフサイクル管理', () {
      test('dispose 時にタイマーが停止される', () {
        // Arrange
        fakeStaticFileClient.setMaintenanceInfo(
          MaintenanceInfoDummy.operational,
        );

        // Act & Assert
        expect(() {
          final tempContainer = ProviderContainer(
            overrides: [
              staticFileClientProvider.overrideWithValue(fakeStaticFileClient),
            ],
          );
          tempContainer.read(maintenanceControllerProvider);
          tempContainer.dispose(); // これで onDispose が呼ばれる
        }, returnsNormally);
      });
    });
  });
}

